#!/usr/bin/env node

/**
 * Update Bundle Metadata Script
 * Updates package.json bundleSize metadata after build
 *
 * This script:
 * 1. Reads bundle-sizes.json generated by check-bundle-size.js
 * 2. Updates package.json bundleSize section with current metrics
 * 3. Provides formatted output for humans and CI/CD
 *
 * Called automatically after: npm run build
 */

const fs = require('fs');
const path = require('path');

const BUNDLE_SIZES_PATH = path.join(__dirname, '../dist/bundle-sizes.json');
const PACKAGE_JSON_PATH = path.join(__dirname, '../package.json');

// ANSI color codes
const colors = {
  reset: '\x1b[0m',
  red: '\x1b[31m',
  green: '\x1b[32m',
  yellow: '\x1b[33m',
  blue: '\x1b[34m',
  bold: '\x1b[1m'
};

function formatBytes(bytes) {
  return `${(bytes / 1024).toFixed(2)} KB`;
}

function updateBundleMetadata() {
  console.log(`${colors.bold}Update Bundle Metadata${colors.reset}`);
  console.log('='.repeat(50));

  // Check if bundle-sizes.json exists
  if (!fs.existsSync(BUNDLE_SIZES_PATH)) {
    console.error(`${colors.red} Error: bundle-sizes.json not found${colors.reset}`);
    console.log(`${colors.yellow}  Run 'npm run size' first to generate bundle sizes${colors.reset}`);
    process.exit(1);
  }

  // Read bundle sizes
  let bundleSizes;
  try {
    const bundleSizesContent = fs.readFileSync(BUNDLE_SIZES_PATH, 'utf8');
    bundleSizes = JSON.parse(bundleSizesContent);
  } catch (error) {
    console.error(`${colors.red} Failed to read bundle-sizes.json: ${error.message}${colors.reset}`);
    process.exit(1);
  }

  // Read package.json
  let packageJson;
  try {
    const packageContent = fs.readFileSync(PACKAGE_JSON_PATH, 'utf8');
    packageJson = JSON.parse(packageContent);
  } catch (error) {
    console.error(`${colors.red} Failed to read package.json: ${error.message}${colors.reset}`);
    process.exit(1);
  }

  // Calculate metrics
  const MAX_SIZE_BYTES = 500 * 1024; // 500KB budget
  const MAX_GZIP_BYTES = 100 * 1024; // 100KB gzip budget
  const utilization = ((bundleSizes.raw / MAX_SIZE_BYTES) * 100).toFixed(2);
  const compressionRatio = ((1 - (bundleSizes.gzipped / bundleSizes.raw)) * 100).toFixed(1);

  // Update package.json bundleSize section
  packageJson.bundleSize = {
    raw: formatBytes(bundleSizes.raw),
    gzipped: formatBytes(bundleSizes.gzipped),
    brotli: formatBytes(bundleSizes.brotli),
    budget: formatBytes(MAX_SIZE_BYTES),
    utilization: `${utilization}%`,
    compressionRatio: `${compressionRatio}%`,
    lastUpdated: new Date().toISOString().split('T')[0], // YYYY-MM-DD
    limits: {
      maxRaw: '500 KB',
      maxGzipped: '100 KB',
      warning: '400 KB',
      error: '500 KB'
    }
  };

  // Write updated package.json
  try {
    fs.writeFileSync(PACKAGE_JSON_PATH, JSON.stringify(packageJson, null, 2) + '\n', 'utf8');
    console.log(`${colors.green} Updated package.json bundleSize metadata${colors.reset}`);
  } catch (error) {
    console.error(`${colors.red} Failed to write package.json: ${error.message}${colors.reset}`);
    process.exit(1);
  }

  // Display summary
  console.log('');
  console.log('Bundle Size Summary:');
  console.log(`  Raw:         ${colors.blue}${formatBytes(bundleSizes.raw)}${colors.reset}`);
  console.log(`  Gzipped:     ${colors.blue}${formatBytes(bundleSizes.gzipped)}${colors.reset}`);
  console.log(`  Brotli:      ${colors.blue}${formatBytes(bundleSizes.brotli)}${colors.reset}`);
  console.log(`  Budget:      ${formatBytes(MAX_SIZE_BYTES)}`);
  console.log(`  Utilization: ${utilization < 80 ? colors.green : colors.yellow}${utilization}%${colors.reset}`);
  console.log(`  Compression: ${colors.green}${compressionRatio}%${colors.reset}`);
  console.log('');

  // Check budget compliance
  if (bundleSizes.raw > MAX_SIZE_BYTES) {
    console.log(`${colors.red}${colors.bold}WARNING:${colors.reset} ${colors.red}Bundle exceeds size budget!${colors.reset}`);
    process.exit(1);
  }

  if (bundleSizes.gzipped > MAX_GZIP_BYTES) {
    console.log(`${colors.yellow}${colors.bold}WARNING:${colors.reset} ${colors.yellow}Gzipped bundle exceeds target${colors.reset}`);
  }

  console.log(`${colors.green}${colors.bold}SUCCESS:${colors.reset} ${colors.green}Bundle metadata updated${colors.reset}`);
  console.log('');
}

// Run the update
updateBundleMetadata();
